/* eslint no-var: off */
var defaultOptions = {
    ignoreSelector: '.js-toc-ignore',
    linkClass: 'toc-link',
    extraLinkClasses: '',
    activeLinkClass: 'is-active-link',
    listClass: 'toc-list',
    extraListClasses: '',
    isCollapsedClass: 'is-collapsed',
    collapsibleClass: 'is-collapsible',
    listItemClass: 'toc-list-item',
    activeListItemClass: 'is-active-li',
    collapseDepth: 0,
    scrollSmooth: true,
    scrollSmoothDuration: 420,
    scrollSmoothOffset: 0,
    scrollEndCallback: function (e) { },
    throttleTimeout: 50,
    positionFixedSelector: null,
    positionFixedClass: 'is-position-fixed',
    fixedSidebarOffset: 'auto',
    includeHtml: false,
    includeTitleTags: false,
    orderedList: true,
    scrollContainer: null,
    skipRendering: false,
    headingLabelCallback: false,
    ignoreHiddenElements: false,
    headingObjectCallback: null,
    basePath: '',
    disableTocScrollSync: false
}

function ParseContent(options) {
    var reduce = [].reduce

    /**
     * Get the last item in an array and return a reference to it.
     * @param {Array} array
     * @return {Object}
     */
    function getLastItem(array) {
        return array[array.length - 1]
    }

    /**
     * Get heading level for a heading dom node.
     * @param {HTMLElement} heading
     * @return {Number}
     */
    function getHeadingLevel(heading) {
        return +heading.nodeName.toUpperCase().replace('H', '')
    }

    /**
     * Get important properties from a heading element and store in a plain object.
     * @param {HTMLElement} heading
     * @return {Object}
     */
    function getHeadingObject(heading) {
        // each node is processed twice by this method because nestHeadingsArray() and addNode() calls it
        // first time heading is real DOM node element, second time it is obj
        // that is causing problem so I am processing only original DOM node
        if (!(heading instanceof window.HTMLElement)) return heading

        if (options.ignoreHiddenElements && (!heading.offsetHeight || !heading.offsetParent)) {
            return null
        }

        const headingLabel = heading.getAttribute('data-heading-label') ||
            (options.headingLabelCallback ? String(options.headingLabelCallback(heading.textContent)) : heading.textContent.trim())
        var obj = {
            id: heading.id,
            children: [],
            nodeName: heading.nodeName,
            headingLevel: getHeadingLevel(heading),
            textContent: headingLabel
        }

        if (options.includeHtml) {
            obj.childNodes = heading.childNodes
        }

        if (options.headingObjectCallback) {
            return options.headingObjectCallback(obj, heading)
        }

        return obj
    }

    /**
     * Add a node to the nested array.
     * @param {Object} node
     * @param {Array} nest
     * @return {Array}
     */
    function addNode(node, nest) {
        var obj = getHeadingObject(node)
        var level = obj.headingLevel
        var array = nest
        var lastItem = getLastItem(array)
        var lastItemLevel = lastItem
            ? lastItem.headingLevel
            : 0
        var counter = level - lastItemLevel

        while (counter > 0) {
            lastItem = getLastItem(array)
            // Handle case where there are multiple h5+ in a row.
            if (lastItem && level === lastItem.headingLevel) {
                break
            } else if (lastItem && lastItem.children !== undefined) {
                array = lastItem.children
            }
            counter--
        }

        if (level >= options.collapseDepth) {
            obj.isCollapsed = true
        }

        array.push(obj)
        return array
    }

    /**
     * Select headings in content area, exclude any selector in options.ignoreSelector
     * @param {HTMLElement} contentElement
     * @param {Array} headingSelector
     * @return {Array}
     */
    function selectHeadings(contentElement, headingSelector) {
        var selectors = headingSelector
        if (options.ignoreSelector) {
            selectors = headingSelector.split(',')
                .map(function mapSelectors(selector) {
                    return selector.trim() + ':not(' + options.ignoreSelector + ')'
                })
        }
        try {
            return contentElement.querySelectorAll(selectors)
        } catch (e) {
            console.warn('Headers not found with selector: ' + selectors); // eslint-disable-line
            return null
        }
    }

    /**
     * Nest headings array into nested arrays with 'children' property.
     * @param {Array} headingsArray
     * @return {Object}
     */
    function nestHeadingsArray(headingsArray) {
        return reduce.call(headingsArray, function reducer(prev, curr) {
            var currentHeading = getHeadingObject(curr)
            if (currentHeading) {
                addNode(currentHeading, prev.nest)
            }
            return prev
        }, {
            nest: []
        })
    }

    return {
        nestHeadingsArray: nestHeadingsArray,
        selectHeadings: selectHeadings
    }
}

function BuildHtml(options) {
    var forEach = [].forEach
    var some = [].some
    var body = document.body
    var tocElement
    var mainContainer = document.querySelector(options.contentSelector)
    var currentlyHighlighting = true
    var SPACE_CHAR = ' '

    /**
     * Create link and list elements.
     * @param {Object} d
     * @param {HTMLElement} container
     * @return {HTMLElement}
     */
    function createEl(d, container) {
        var link = container.appendChild(createLink(d))
        if (d.children.length) {
            var list = createList(d.isCollapsed)
            d.children.forEach(function (child) {
                createEl(child, list)
            })
            link.appendChild(list)
        }
    }

    /**
     * Render nested heading array data into a given element.
     * @param {HTMLElement} parent Optional. If provided updates the {@see tocElement} to match.
     * @param {Array} data
     * @return {HTMLElement}
     */
    function render(parent, data) {
        var collapsed = false
        var container = createList(collapsed)

        data.forEach(function (d) {
            createEl(d, container)
        })

        // Return if no TOC element is provided or known.
        tocElement = parent || tocElement
        if (tocElement === null) {
            return
        }

        // Remove existing child if it exists.
        if (tocElement.firstChild) {
            tocElement.removeChild(tocElement.firstChild)
        }

        // Just return the parent and don't append the list if no links are found.
        if (data.length === 0) {
            return tocElement
        }

        // Append the Elements that have been created
        return tocElement.appendChild(container)
    }

    /**
     * Create link element.
     * @param {Object} data
     * @return {HTMLElement}
     */
    function createLink(data) {
        var item = document.createElement('li')
        var a = document.createElement('a')
        if (options.listItemClass) {
            item.setAttribute('class', options.listItemClass)
        }

        if (options.onClick) {
            a.onclick = options.onClick
        }

        if (options.includeTitleTags) {
            a.setAttribute('title', data.textContent)
        }

        if (options.includeHtml && data.childNodes.length) {
            forEach.call(data.childNodes, function (node) {
                a.appendChild(node.cloneNode(true))
            })
        } else {
            // Default behavior.
            a.textContent = data.textContent
        }
        a.setAttribute('href', options.basePath + '#' + data.id)
        a.setAttribute('class', options.linkClass +
            SPACE_CHAR + 'node-name--' + data.nodeName +
            SPACE_CHAR + options.extraLinkClasses)
        item.appendChild(a)
        return item
    }

    /**
     * Create list element.
     * @param {Boolean} isCollapsed
     * @return {HTMLElement}
     */
    function createList(isCollapsed) {
        var listElement = (options.orderedList) ? 'ol' : 'ul'
        var list = document.createElement(listElement)
        var classes = options.listClass +
            SPACE_CHAR + options.extraListClasses
        if (isCollapsed) {
            classes += SPACE_CHAR + options.collapsibleClass
            classes += SPACE_CHAR + options.isCollapsedClass
        }
        list.setAttribute('class', classes)
        return list
    }

    /**
     * Update fixed sidebar class.
     * @return {HTMLElement}
     */
    function updateFixedSidebarClass() {
        if (options.scrollContainer && document.querySelector(options.scrollContainer)) {
            var top
            top = document.querySelector(options.scrollContainer).scrollTop
        } else {
            top = document.documentElement.scrollTop || body.scrollTop
        }
        var posFixedEl = document.querySelector(options.positionFixedSelector)

        if (options.fixedSidebarOffset === 'auto') {
            options.fixedSidebarOffset = tocElement.offsetTop
        }

        if (top > options.fixedSidebarOffset) {
            if (posFixedEl.className.indexOf(options.positionFixedClass) === -1) {
                posFixedEl.className += SPACE_CHAR + options.positionFixedClass
